import React, { useState } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";

export default function AdminNavbar() {
  const [navbarOpen, setNavbarOpen] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();

  // تحديد الصفحة النشطة
  const isActive = (path) => {
    return location.pathname === path;
  };

  // روابط التنقل
  const navLinks = [
    { path: "/profile", name: "الملف الشخصي", icon: "👤", label: "Profile" },
    { path: "/restaurants", name: "المطاعم", icon: "🍕", label: "Restaurants" },
    { path: "/workers", name: "العمال", icon: "👨‍🍳", label: "Workers" },
  ];

  return (
    <>
      {/* Navbar */}
      <nav className="fixed top-0 z-50 w-full bg-gradient-to-r from-gray-900 via-gray-800 to-gray-900 shadow-lg border-b border-gray-700">
        <div className="px-4 mx-auto max-w-7xl sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">
            {/* Logo - يسار الشاشة */}
            <div className="flex items-center">
              <Link to="/profile" className="flex items-center space-x-2 rtl:space-x-reverse">
                <div className="w-8 h-8 bg-gradient-to-br from-green-400 to-emerald-600 rounded-lg flex items-center justify-center">
                  <span className="text-white font-bold text-lg">م</span>
                </div>
                <span className="text-white font-bold text-lg hidden sm:block">
                  منصة إدارة المطاعم
                </span>
                <span className="text-white font-bold text-lg sm:hidden">
                  مطاعم
                </span>
              </Link>
            </div>

            {/* Desktop Menu - وسط الشاشة */}
            <div className="hidden md:flex items-center justify-center flex-1 mx-4">
              <div className="flex space-x-2 rtl:space-x-reverse bg-gray-800/50 rounded-xl p-1">
                {navLinks.map((link) => (
                  <Link
                    key={link.path}
                    to={link.path}
                    className={`
                      flex items-center gap-2 px-4 py-2 rounded-lg transition-all duration-200
                      ${isActive(link.path) 
                        ? "bg-gradient-to-r from-green-500 to-emerald-600 text-white shadow-lg" 
                        : "text-gray-300 hover:bg-gray-700 hover:text-white"
                      }
                    `}
                  >
                    <span className="text-lg">{link.icon}</span>
                    <span className="font-medium">{link.name}</span>
                    {isActive(link.path) && (
                      <span className="w-1.5 h-1.5 bg-white rounded-full animate-pulse"></span>
                    )}
                  </Link>
                ))}
              </div>
            </div>

            {/* زر إدارة الجلسة - يمين الشاشة */}
            <div className="hidden md:flex items-center space-x-3 rtl:space-x-reverse">
              <button
                onClick={() => alert("تسجيل الخروج")}
                className="flex items-center gap-2 px-3 py-2 text-sm text-gray-300 bg-gray-800 rounded-lg hover:bg-gray-700 hover:text-white transition-all duration-200"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
                </svg>
                <span className="hidden lg:inline">تسجيل خروج</span>
              </button>
            </div>

            {/* Mobile Menu Button - زر القائمة للجوال */}
            <div className="flex md:hidden">
              <button
                onClick={() => setNavbarOpen(!navbarOpen)}
                className="inline-flex items-center justify-center p-2 rounded-md text-gray-400 hover:text-white hover:bg-gray-700 focus:outline-none focus:ring-2 focus:ring-inset focus:ring-white"
              >
                <span className="sr-only">فتح القائمة</span>
                {!navbarOpen ? (
                  <svg className="block w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16" />
                  </svg>
                ) : (
                  <svg className="block w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
                  </svg>
                )}
              </button>
            </div>
          </div>
        </div>

        {/* Mobile Menu - القائمة المنبثقة للجوال */}
        <div className={`md:hidden transition-all duration-300 ease-in-out ${navbarOpen ? 'max-h-64 opacity-100' : 'max-h-0 opacity-0 overflow-hidden'}`}>
          <div className="px-2 pt-2 pb-3 space-y-1 bg-gray-800/95 backdrop-blur-sm border-t border-gray-700">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                onClick={() => setNavbarOpen(false)}
                className={`
                  flex items-center gap-3 px-3 py-2 rounded-lg transition-all duration-200
                  ${isActive(link.path) 
                    ? "bg-gradient-to-r from-green-500 to-emerald-600 text-white" 
                    : "text-gray-300 hover:bg-gray-700 hover:text-white"
                  }
                `}
              >
                <span className="text-xl">{link.icon}</span>
                <span className="font-medium">{link.name}</span>
                {isActive(link.path) && (
                  <span className="mr-auto text-xs">●</span>
                )}
              </Link>
            ))}
            
            {/* زر تسجيل الخروج في الجوال */}
            <button
              onClick={() => {
                setNavbarOpen(false);
                alert("تسجيل الخروج");
              }}
              className="flex items-center gap-3 w-full px-3 py-2 rounded-lg text-gray-300 hover:bg-gray-700 hover:text-white transition-all duration-200"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
              </svg>
              <span>تسجيل خروج</span>
            </button>
          </div>
        </div>
      </nav>

      {/* Spacer to prevent content from hiding under navbar */}
      <div className="h-16"></div>
    </>
  );
}
